// Live Postgres integration tests for the reference task store adapter.
//
// These run only when a Postgres URL is available (A2A_TEST_DATABASE_URL or
// DATABASE_URL). The CI "Unit tests" job already provisions a postgres service
// and exports DATABASE_URL, so these execute there; locally they skip unless a
// database is provided. `pg` is a devDependency and is imported lazily so the
// file loads cleanly even when it is not installed.

import { describe, it, before, after, beforeEach } from "node:test";
import assert from "node:assert/strict";

import {
  createPostgresTaskStore,
  ensurePostgresTaskStoreSchema,
  runTaskStoreMigrations,
  TASK_STORE_MIGRATIONS,
} from "portauth-a2a-receiver";

const DB_URL = process.env.A2A_TEST_DATABASE_URL || process.env.DATABASE_URL || "";
const TABLE = "portauth_a2a_tasks_it";

let counter = 0;
function pending(overrides = {}) {
  counter += 1;
  return {
    id: `rec-${counter}-${Math.random().toString(36).slice(2)}`,
    taskId: "task-1",
    idempotencyKey: `idem-${counter}-${Math.random().toString(36).slice(2)}`,
    lifecycleState: "pending",
    task: { id: "task-1", status: { state: "TASK_STATE_SUBMITTED" } },
    response: null,
    requestContext: { action: "demo:do", resource: "urn:demo:1" },
    presenterId: "agent:1",
    vcFormat: "tier1-jwt",
    auditRecordId: null,
    errorReason: null,
    ...overrides,
  };
}

describe(
  "Postgres task store (live)",
  { skip: DB_URL ? false : "set A2A_TEST_DATABASE_URL or DATABASE_URL to run live Postgres tests" },
  () => {
    let pool;
    let store;

    before(async () => {
      const pg = (await import("pg")).default;
      pool = new pg.Pool({ connectionString: DB_URL });
      await pool.query(`DROP TABLE IF EXISTS "${TABLE}"`);
      await pool.query(`DROP TABLE IF EXISTS "${TABLE}_migrations"`);
      await ensurePostgresTaskStoreSchema(pool, { tableName: TABLE });
      store = createPostgresTaskStore({ queryable: pool, tableName: TABLE });
    });

    after(async () => {
      if (pool) {
        await pool.query(`DROP TABLE IF EXISTS "${TABLE}"`);
        await pool.query(`DROP TABLE IF EXISTS "${TABLE}_migrations"`);
        await pool.end();
      }
    });

    beforeEach(async () => {
      await store.clear();
    });

    it("creates a pending record and round-trips JSON columns", async () => {
      const rec = pending();
      const { created, record } = await store.createPending(rec);
      assert.equal(created, true);
      assert.equal(record.lifecycleState, "pending");

      const got = await store.get(rec.id);
      assert.equal(got.idempotencyKey, rec.idempotencyKey);
      assert.deepEqual(got.requestContext, rec.requestContext);
      assert.deepEqual(got.task, rec.task);

      const byKey = await store.getByIdempotencyKey(rec.idempotencyKey);
      assert.equal(byKey.id, rec.id);
    });

    it("dedupes a duplicate idempotency key instead of inserting twice", async () => {
      const rec = pending();
      const first = await store.createPending(rec);
      assert.equal(first.created, true);

      const second = await store.createPending(pending({ idempotencyKey: rec.idempotencyKey }));
      assert.equal(second.created, false);
      assert.equal(second.record.id, rec.id);
    });

    it("resolves a concurrent createPending race on the same idempotency key", async () => {
      const key = `idem-race-${Date.now()}`;
      const results = await Promise.all([
        store.createPending(pending({ idempotencyKey: key })),
        store.createPending(pending({ idempotencyKey: key })),
      ]);
      const createdCount = results.filter((r) => r.created).length;
      assert.equal(createdCount, 1, "exactly one insert wins the unique-constraint race");
      const ids = new Set(results.map((r) => r.record.id));
      assert.equal(ids.size, 1, "both callers observe the same surviving record");
    });

    it("applies a partial update atomically without clobbering untouched columns", async () => {
      const rec = pending();
      await store.createPending(rec);

      const updated = await store.update(rec.id, { lifecycleState: "completed", auditRecordId: "ar-9" });
      assert.equal(updated.lifecycleState, "completed");
      assert.equal(updated.auditRecordId, "ar-9");
      // Columns not present in the patch are left intact.
      assert.deepEqual(updated.requestContext, rec.requestContext);
      assert.equal(updated.presenterId, rec.presenterId);
      assert.equal(updated.vcFormat, rec.vcFormat);
    });

    it("does not lose writes under concurrent updates of different columns", async () => {
      // The old read-then-write update() would clobber one of these: each writer
      // read the same pending row and wrote back every column. The atomic
      // single-statement update touches only its own columns, so both land.
      const rec = pending();
      await store.createPending(rec);

      await Promise.all([
        store.update(rec.id, { auditRecordId: "ar-a" }),
        store.update(rec.id, { lifecycleState: "completed" }),
      ]);

      const got = await store.get(rec.id);
      assert.equal(got.lifecycleState, "completed");
      assert.equal(got.auditRecordId, "ar-a");
    });

    it("getByTaskId returns the most recently updated record for a task", async () => {
      const a = pending({ taskId: "task-multi" });
      const b = pending({ taskId: "task-multi" });
      await store.createPending(a);
      await store.createPending(b);
      // Touch `a` last so it has the newest updated_at.
      await store.update(a.id, { lifecycleState: "completed" });

      const latest = await store.getByTaskId("task-multi");
      assert.equal(latest.id, a.id);
    });

    it("list respects the limit and orders newest first", async () => {
      await store.createPending(pending());
      await store.createPending(pending());
      await store.createPending(pending());

      const limited = await store.list({ limit: 2 });
      assert.equal(limited.length, 2);
      assert.ok(limited[0].updatedAt >= limited[1].updatedAt);
    });

    it("re-running the schema is idempotent", async () => {
      const result = await ensurePostgresTaskStoreSchema(pool, { tableName: TABLE });
      assert.deepEqual(result.applied, [], "no migrations should be pending on a current schema");
      // Still usable after a second migration pass.
      const rec = pending();
      const { created } = await store.createPending(rec);
      assert.equal(created, true);
    });

    it("records every applied migration version in the ledger", async () => {
      const ledger = await pool.query(`SELECT version, name FROM "${TABLE}_migrations" ORDER BY version`);
      const versions = ledger.rows.map((row) => Number(row.version));
      assert.deepEqual(versions, TASK_STORE_MIGRATIONS.map((m) => m.version));
    });

    it("applies pending migrations from a clean database in order", async () => {
      const freshTable = "portauth_a2a_tasks_mig";
      await pool.query(`DROP TABLE IF EXISTS "${freshTable}"`);
      await pool.query(`DROP TABLE IF EXISTS "${freshTable}_migrations"`);
      try {
        const first = await runTaskStoreMigrations(pool, { tableName: freshTable });
        assert.deepEqual(first.applied, TASK_STORE_MIGRATIONS.map((m) => m.version));
        // Second run is a no-op — only pending migrations are applied.
        const second = await runTaskStoreMigrations(pool, { tableName: freshTable });
        assert.deepEqual(second.applied, []);
        // The migrated table is fully usable (task_id column from migration 2 exists).
        const migratedStore = createPostgresTaskStore({ queryable: pool, tableName: freshTable });
        const rec = pending({ taskId: "task-mig" });
        await migratedStore.createPending(rec);
        const byTask = await migratedStore.getByTaskId("task-mig");
        assert.equal(byTask.id, rec.id);
      } finally {
        await pool.query(`DROP TABLE IF EXISTS "${freshTable}"`);
        await pool.query(`DROP TABLE IF EXISTS "${freshTable}_migrations"`);
      }
    });
  },
);
